ee:message.ee:set-payload:
%dw 2.0
import dw::util::Pagination
output application/json
---
var result = Pagination::paginate(payload, vars.pageSize, vars.afterCursor, vars.beforeCursor)
---
{
	paging: {
		cursors: {
			before: result.before,
			after: result.after
		},
		hasNext: result.after != null,
		hasPrevious: result.before != null,
		limit: vars.pageSize
	},
	results: result.data map {
		id: $.UUID__c,
		name: $.Name,
		email: $.Email__c,
		phone: $.Phone__c default null,
		website: $.Website__c default null,
		status: $.Status__c
	}
}
